+  menu.append(
     makeActionButton('Move', async () => {
       const dest = window.prompt('Move to relative destination path:', entry.path);
       if (dest === null) {
@@ -137,7 +179,7 @@ export function makeBrowseRow(entry: FileEntry): HTMLTableRowElement {
